import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import {
  Button,
  Input,
  Modal,
  Select,
  SearchTextInput,
  dispatchAppToast,
  useViewMobileLayout,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { WorkShiftDto } from '../../../services/ns/models';
import { caLamViecPageLabels as labels } from '../../../constants/caLamViecPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import {
  getErpListRowMenuHint,
  catalogListRowMenuHintDismissStorageKey,
} from '../../../utils/catalogListRowMenuHint';
import { useCatalogListPermissions } from '../../../hooks/useCatalogListPermissions';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import {
  CatalogListMasterLinPageLayout,
  CatalogRowActionMenu,
  useCatalogListPaging,
  useCatalogTableBusy,
  type CatalogBatchDeleteMode,
  type CatalogListToolbarBridge,
  type CatalogRowMenuAction,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
} from '../../../components/catalog/catalogUiSchema';
import { hrCatalogDocumentTypes } from '../../../config/documentHistoryClients';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-ca-lam-viec';
const PAGE_ID = 'ns-ca-lam-viec';
const CATALOG_KIND = 'hr-work-shifts';

const emptyShift = {
  code: '',
  name: '',
  startTime: '08:00',
  endTime: '17:00',
  workHours: 8,
  isActive: true,
};

type ModalMode = 'create' | 'edit' | 'view';

const ACTIVE_OPTIONS = [
  { value: '', label: 'Tất cả trạng thái' },
  { value: 'true', label: 'Hoạt động' },
  { value: 'false', label: 'Tắt' },
];

const ACTIVE_FORM_OPTIONS = [
  { value: 'true', label: 'Hoạt động' },
  { value: 'false', label: 'Tắt' },
];

const CaLamViecPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const viewMobile = useViewMobileLayout();
  const { canWrite } = useCatalogListPermissions(CATALOG_KIND);
  const toolbarBridgeRef = useRef<CatalogListToolbarBridge | null>(null);
  const [reloadKey, setReloadKey] = useState(0);
  const [allShifts, setAllShifts] = useState<WorkShiftDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [activeFilter, setActiveFilter] = useState('');
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: WorkShiftDto } | null>(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>('create');
  const [editing, setEditing] = useState<WorkShiftDto | null>(null);
  const [form, setForm] = useState(emptyShift);
  const [saving, setSaving] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);

  const { schema, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const filteredShifts = useMemo(() => {
    let list = allShifts;
    if (search) {
      const q = search.toLowerCase();
      list = list.filter(
        s =>
          s.code.toLowerCase().includes(q) ||
          s.name.toLowerCase().includes(q) ||
          (s.legacyId != null && String(s.legacyId).includes(q)),
      );
    }
    if (activeFilter !== '') {
      list = list.filter(s => s.isActive === (activeFilter === 'true'));
    }
    return list;
  }, [allShifts, search, activeFilter]);

  const totalCount = filteredShifts.length;

  const items = useMemo(() => {
    const start = (page - 1) * pageSize;
    return filteredShifts.slice(start, start + pageSize);
  }, [filteredShifts, page, pageSize]);

  const selection = useCatalogListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = useCallback(() => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  }, [selection]);

  const handleSearch = useCallback(() => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  }, [pulseSearch, searchDraft, resetPage, selection]);

  const openModal = useCallback((mode: ModalMode, row?: WorkShiftDto) => {
    setModalMode(mode);
    setEditing(row ?? null);
    setDeleteConfirm(false);
    if (row) {
      setForm({
        code: row.code,
        name: row.name,
        startTime: row.startTime?.slice(0, 5) ?? '08:00',
        endTime: row.endTime?.slice(0, 5) ?? '17:00',
        workHours: row.workHours,
        isActive: row.isActive,
      });
    } else {
      setForm(emptyShift);
    }
    setModalOpen(true);
  }, []);

  const openView = useCallback((row: WorkShiftDto) => openModal('view', row), [openModal]);

  const openEdit = useCallback(
    (row: WorkShiftDto) => {
      if (!canWrite) {
        openView(row);
        return;
      }
      openModal('edit', row);
    },
    [canWrite, openModal, openView],
  );

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService
        .getWorkShifts()
        .then(data => {
          if (!cancelled) setAllShifts(data);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [dispatch, reloadKey]);

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: WorkShiftDto; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: CatalogRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          openView(row);
          break;
        case 'edit':
          openEdit(row);
          break;
        case 'history':
          toolbarBridgeRef.current?.openHistory();
          break;
        case 'delete':
          if (!selection.isRowChecked(row)) {
            selection.toggleRow(row, true);
          }
          toolbarBridgeRef.current?.openDelete();
          break;
        default:
          break;
      }
    },
    [rowMenu?.row, openEdit, openView, selection],
  );

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? filteredShifts.map(r => r.id)
        : [...selection.selectedIds];
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(
        ids.map(id => {
          const row = allShifts.find(r => r.id === id)!;
          return hrService.updateWorkShift(id, {
            name: row.name,
            startTime: row.startTime?.slice(0, 5) ?? '08:00',
            endTime: row.endTime?.slice(0, 5) ?? '17:00',
            workHours: row.workHours,
            isActive: false,
          });
        }),
      );
      dispatchAppToast(dispatch, {
        message: `Đã tắt ${ids.length} ca làm việc`,
        type: 'success',
      });
    } else {
      await Promise.all(ids.map(id => hrService.deleteWorkShift(id)));
      dispatchAppToast(dispatch, {
        message: `Đã xóa ${ids.length} ca làm việc`,
        type: 'success',
      });
    }
    refresh();
  };

  const handleSave = async () => {
    if (modalMode === 'view') return;
    if (!form.code.trim() || !form.name.trim()) {
      dispatchAppToast(dispatch, { message: labels.codeNameRequired, type: 'error' });
      return;
    }
    setSaving(true);
    try {
      if (modalMode === 'edit' && editing) {
        await hrService.updateWorkShift(editing.id, {
          name: form.name,
          startTime: form.startTime,
          endTime: form.endTime,
          workHours: form.workHours,
          isActive: form.isActive,
        });
        dispatchAppToast(dispatch, { message: labels.updateSuccess, type: 'success' });
      } else {
        await hrService.createWorkShift({
          code: form.code.trim().toUpperCase(),
          name: form.name.trim(),
          startTime: form.startTime,
          endTime: form.endTime,
          workHours: form.workHours,
        });
        dispatchAppToast(dispatch, { message: labels.createSuccess, type: 'success' });
      }
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!editing || !canWrite) return;
    try {
      await hrService.deleteWorkShift(editing.id);
      dispatchAppToast(dispatch, { message: labels.deleteSuccess, type: 'success' });
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.deleteError),
        type: 'error',
      });
    }
  };

  const readOnly = modalMode === 'view';
  const modalTitle =
    modalMode === 'create'
      ? labels.modalAddTitle
      : modalMode === 'edit'
        ? labels.modalEditTitle
        : labels.modalViewTitle;

  const rowMenuRow = rowMenu?.row;
  const rowMenuShowEdit = !!rowMenuRow && canWrite;
  const rowMenuShowView = !!rowMenuRow && !canWrite;
  const rowMenuHintMessage = getErpListRowMenuHint(viewMobile);

  const filterBar = (
    <>
      <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
        <SearchTextInput
          label="Tìm kiếm"
          placeholder={labels.searchPlaceholder}
          value={searchDraft}
          onChange={setSearchDraft}
          onSearch={handleSearch}
          testId={`${TEST_ID}-search-text`}
        />
      </div>
      <div className={styles.field} data-testid={`${TEST_ID}-field-active`}>
        <Select
          label="Trạng thái"
          value={activeFilter}
          onChange={e => {
            setActiveFilter(e.target.value);
            resetPage();
            selection.clearSelection();
          }}
          options={ACTIVE_OPTIONS}
          fullWidth
        />
      </div>
    </>
  );

  return (
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        catalogKind={CATALOG_KIND}
        documentType={hrCatalogDocumentTypes[CATALOG_KIND]}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={items}
        onAdd={() => openModal('create')}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        toolbarBridgeRef={toolbarBridgeRef}
        page={page}
        pageSize={pageSize}
        onPageChange={p => {
          setPage(p);
          selection.clearSelection();
        }}
        onPageSizeChange={setPageSize}
        showTableLoading={showTableLoading}
        header={{
          title: labels.listTitle,
          titleIconClass: 'fas fa-business-time',
          pageId: PAGE_ID,
        }}
        listTitle={labels.listSubtitle}
        listRowMenuHelp
        filters={filterBar}
        filterMaxWidthPx={1000}
        schemaEditorModal={
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => reloadSchema()}
          />
        }
        extraModals={
          <CatalogRowActionMenu
            open={rowMenu != null}
            x={rowMenu?.x ?? 0}
            y={rowMenu?.y ?? 0}
            onClose={() => setRowMenu(null)}
            onSelect={handleRowMenuSelect}
            testIdPrefix={TEST_ID}
            showEdit={rowMenuShowEdit}
            showView={rowMenuShowView}
            showHistory={!!rowMenuRow}
            showDelete={rowMenuShowEdit}
          />
        }
      >
        {items.length === 0 ? (
          <div className={styles.empty} data-testid={`${TEST_ID}-empty`}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy ca làm việc phù hợp' : labels.empty}</p>
          </div>
        ) : listColumns.length > 0 ? (
          <CatalogListGridFromSchema
            testIdPrefix={TEST_ID}
            rows={items}
            page={page}
            pageSize={pageSize}
            columns={listColumns}
            schema={schema}
            selection={selection}
            getRowId={r => r.id}
            onRowOpenActionMenu={handleRowOpenActionMenu}
            rowMenuHintMessage={rowMenuHintMessage}
            rowMenuHintDismissStorageKey={catalogListRowMenuHintDismissStorageKey(TEST_ID)}
            enableRowMenuLongPress={viewMobile}
          />
        ) : null}
      </CatalogListMasterLinPageLayout>

      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={modalTitle}>
        <div className={styles.modalBody}>
          <div className={styles.field}>
            <label className={styles.label}>Mã ca *</label>
            <Input
              value={form.code}
              onChange={e => setForm(f => ({ ...f, code: e.target.value.toUpperCase() }))}
              disabled={readOnly || modalMode !== 'create'}
              data-testid={`${TEST_ID}-field-code`}
            />
          </div>
          {editing?.legacyId != null ? (
            <div className={styles.field} data-testid={`${TEST_ID}-legacy-id`}>
              <label className={styles.label}>{labels.legacyIdLabel}</label>
              <span
                style={{ color: 'var(--linm-color-legacy-code, #ca8a04)', fontSize: 14 }}
                data-testid={`${TEST_ID}-legacy-id-value`}
              >
                {editing.legacyId}
              </span>
            </div>
          ) : null}
          <div className={styles.field}>
            <label className={styles.label}>Tên ca *</label>
            <Input
              value={form.name}
              onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
              disabled={readOnly}
              data-testid={`${TEST_ID}-field-name`}
            />
          </div>
          <div className={styles.formGrid}>
            <div className={styles.field}>
              <label className={styles.label}>Giờ vào</label>
              <Input
                type="time"
                value={form.startTime}
                onChange={e => setForm(f => ({ ...f, startTime: e.target.value }))}
                disabled={readOnly}
                data-testid={`${TEST_ID}-field-start`}
              />
            </div>
            <div className={styles.field}>
              <label className={styles.label}>Giờ ra</label>
              <Input
                type="time"
                value={form.endTime}
                onChange={e => setForm(f => ({ ...f, endTime: e.target.value }))}
                disabled={readOnly}
                data-testid={`${TEST_ID}-field-end`}
              />
            </div>
            <div className={styles.field}>
              <label className={styles.label}>Giờ công</label>
              <Input
                type="number"
                value={String(form.workHours)}
                onChange={e => setForm(f => ({ ...f, workHours: Number(e.target.value) }))}
                disabled={readOnly}
                data-testid={`${TEST_ID}-field-hours`}
              />
            </div>
          </div>
          {modalMode === 'edit' ? (
            <div className={styles.field}>
              <Select
                label="Trạng thái"
                value={form.isActive ? 'true' : 'false'}
                onChange={e => setForm(f => ({ ...f, isActive: e.target.value === 'true' }))}
                options={ACTIVE_FORM_OPTIONS}
                fullWidth
                data-testid={`${TEST_ID}-field-active`}
              />
            </div>
          ) : null}
          <div className={styles.modalActions}>
            {modalMode === 'edit' && canWrite ? (
              deleteConfirm ? (
                <>
                  <Button
                    variant="danger"
                    onClick={handleDelete}
                    data-testid={`${TEST_ID}-delete-confirm`}
                  >
                    Xác nhận xóa
                  </Button>
                  <Button variant="secondary" onClick={() => setDeleteConfirm(false)}>
                    Huỷ xóa
                  </Button>
                </>
              ) : (
                <Button
                  variant="danger"
                  onClick={() => setDeleteConfirm(true)}
                  data-testid={`${TEST_ID}-delete`}
                >
                  Xóa
                </Button>
              )
            ) : null}
            <span style={{ flex: 1 }} />
            <Button variant="secondary" onClick={() => setModalOpen(false)}>
              {readOnly ? 'Đóng' : 'Huỷ'}
            </Button>
            {!readOnly ? (
              <Button
                variant="primary"
                onClick={handleSave}
                disabled={saving || (modalMode === 'create' && !canWrite) || (modalMode === 'edit' && !canWrite)}
                data-testid={`${TEST_ID}-save`}
              >
                {saving ? 'Đang lưu...' : 'Lưu'}
              </Button>
            ) : null}
          </div>
        </div>
      </Modal>
    </>
  );
};

export default CaLamViecPage;
